export default {
  head() {
    return {
      title: this.$store.getters.headTitle,
      link: [{ rel: "icon", type: "image/x-icon", href: this.$store.getters.favicon}],
    };
  },
  async asyncData({$get, $post}) {
    let categoryList = [];
    let currentId = 0;
    let articleList = [];
    let count = 0;
    let dataNull = true;
    const banner = $get("ad/lists", { params: { pid: 8, client: 2 } });
    let res = await $get("article/category");
    const { data: bannerList } = await banner;
    if(res.code == 1) {
      categoryList = res.data;
      currentId = 0
      let listsRes = await $get("article/lists", {params: {id: currentId, page_size: 10}});
      if(listsRes.code == 1) {
        articleList = listsRes.data.list;
        count = listsRes.data.count
        if(count <= 0) {
          dataNull = true;
        }
        else {
          dataNull = false
        }
      }
    }
    return {
      categoryList,
      articleList,
      count,
      currentId,
      bannerList,
      dataNull,
    }
  },
  data() {
    return {
      categoryList: [],
      articleList: [],
      currentId: -1,
      count: 0,
      swiperOptions: {
        width: 1180,
      }
    }
  },
  mounted() {
    console.log(this.articleList, 'articleList')
  },
  methods: {
    async changePage(current) {
      let res = await this.$get("article/lists", {params: {id: this.currentId, page_no: current, page_size: 10}});
      if(res.code == 1) {
        this.articleList = res.data.list;
        if(this.articleList.length <= 0) {
          dataNull = true;
        }
        else {
          dataNull = false
        }
      }
    },
    changeList(id) {
      this.currentId = id;
      this.changePage(1)
    }
  }
}
